type State = { count: number };

type Action = { type: 'increment' } | { type: 'decrement' };

function counter(state: State, action: Action): State {
  switch (action.type) {
    case 'increment':
      return { count: state.count + 1 };
    case 'decrement':
      return { count: state.count - 1 };
    default:
      return state;
  }
}

import { useDispatch, useSelector } from 'react-redux';
import type { RootState, AppDispatch } from './store';

export function Counter() {
  const count = useSelector((s: RootState) => s.counter.value);
  const dispatch = useDispatch<AppDispatch>();
  return (
    <button type="button" onClick={() => dispatch({ type: 'counter/increment' })}>
      {count}
    </button>
  );
}

import { createSlice } from '@reduxjs/toolkit';

const slice = createSlice({
  name: 'counter',
  initialState: { value: 0 },
  reducers: {
    increment: (state) => {
      state.value += 1;
    },
  },
});

export const { increment } = slice.actions;
export default slice.reducer;

import { createAsyncThunk } from '@reduxjs/toolkit';

export const fetchUser = createAsyncThunk(
  'user/fetch',
  async (userId: string, { rejectWithValue }) => {
    const res = await fetch(`/api/users/${userId}`);
    if (!res.ok) return rejectWithValue(await res.text());
    return res.json();
  }
);
